import type { ComponentProps, ComponentRef } from 'react';
import { Slider as SliderPrimitive, useSlider, useSliderContext } from '@ark-ui/react/slider';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Slider.module.css';

const SliderRoot = forwardRef<
  ComponentRef<typeof SliderPrimitive.Root>,
  ComponentProps<typeof SliderPrimitive.Root>
>(function SliderRoot({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Root
      ref={ref}
      data-slot="slider-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderRootProvider = forwardRef<
  ComponentRef<typeof SliderPrimitive.RootProvider>,
  ComponentProps<typeof SliderPrimitive.RootProvider>
>(function SliderRootProvider({ className, ...props }, ref) {
  return (
    <SliderPrimitive.RootProvider
      ref={ref}
      data-slot="slider-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderLabel = forwardRef<
  ComponentRef<typeof SliderPrimitive.Label>,
  ComponentProps<typeof SliderPrimitive.Label>
>(function SliderLabel({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Label
      ref={ref}
      data-slot="slider-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderValueText = forwardRef<
  ComponentRef<typeof SliderPrimitive.ValueText>,
  ComponentProps<typeof SliderPrimitive.ValueText>
>(function SliderValueText({ className, ...props }, ref) {
  return (
    <SliderPrimitive.ValueText
      ref={ref}
      data-slot="slider-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderControl = forwardRef<
  ComponentRef<typeof SliderPrimitive.Control>,
  ComponentProps<typeof SliderPrimitive.Control>
>(function SliderControl({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Control
      ref={ref}
      data-slot="slider-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderTrack = forwardRef<
  ComponentRef<typeof SliderPrimitive.Track>,
  ComponentProps<typeof SliderPrimitive.Track>
>(function SliderTrack({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Track
      ref={ref}
      data-slot="slider-track"
      className={clsx(styles.track, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderRange = forwardRef<
  ComponentRef<typeof SliderPrimitive.Range>,
  ComponentProps<typeof SliderPrimitive.Range>
>(function SliderRange({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Range
      ref={ref}
      data-slot="slider-range"
      className={clsx(styles.range, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderThumb = forwardRef<
  ComponentRef<typeof SliderPrimitive.Thumb>,
  ComponentProps<typeof SliderPrimitive.Thumb>
>(function SliderThumb({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Thumb
      ref={ref}
      data-slot="slider-thumb"
      className={clsx(styles.thumb, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderHiddenInput = forwardRef<
  ComponentRef<typeof SliderPrimitive.HiddenInput>,
  ComponentProps<typeof SliderPrimitive.HiddenInput>
>(function SliderHiddenInput({ className, ...props }, ref) {
  return (
    <SliderPrimitive.HiddenInput
      ref={ref}
      data-slot="slider-hidden-input"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

function SliderThumbs({ className }: { className?: string }) {
  const slider = useSliderContext();

  return slider.value.map((_, index) => (
    <SliderThumb key={index} index={index} className={className}>
      <SliderHiddenInput />
    </SliderThumb>
  ));
}

const SliderMarkerGroup = forwardRef<
  ComponentRef<typeof SliderPrimitive.MarkerGroup>,
  ComponentProps<typeof SliderPrimitive.MarkerGroup>
>(function SliderMarkerGroup({ className, ...props }, ref) {
  return (
    <SliderPrimitive.MarkerGroup
      ref={ref}
      data-slot="slider-marker-group"
      className={clsx(styles.markerGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderMarker = forwardRef<
  ComponentRef<typeof SliderPrimitive.Marker>,
  ComponentProps<typeof SliderPrimitive.Marker>
>(function SliderMarker({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Marker
      ref={ref}
      data-slot="slider-marker"
      className={clsx(styles.marker, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderDraggingIndicator = forwardRef<
  ComponentRef<typeof SliderPrimitive.DraggingIndicator>,
  ComponentProps<typeof SliderPrimitive.DraggingIndicator>
>(function SliderDraggingIndicator({ className, ...props }, ref) {
  return (
    <SliderPrimitive.DraggingIndicator
      ref={ref}
      data-slot="slider-dragging-indicator"
      className={clsx(styles.draggingIndicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const Slider = Object.assign(SliderRoot, {
  Root: SliderRoot,
  RootProvider: SliderRootProvider,
  Context: SliderPrimitive.Context,
  useSlider,
  useSliderContext,
  Label: SliderLabel,
  ValueText: SliderValueText,
  Control: SliderControl,
  Track: SliderTrack,
  Range: SliderRange,
  Thumb: SliderThumb,
  Thumbs: SliderThumbs,
  HiddenInput: SliderHiddenInput,
  MarkerGroup: SliderMarkerGroup,
  Marker: SliderMarker,
  DraggingIndicator: SliderDraggingIndicator,
});

export { Slider, useSlider, useSliderContext };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    gap: var(--slider-gap, 0.5rem);
    width: var(--slider-width, 12rem);
    color: var(--slider-color, var(--color-foreground));

    &[data-orientation='vertical'] {
      width: var(--slider-width-vertical, max-content);
      height: var(--slider-height, 12rem);
      align-items: center;
    }

    &[data-disabled] {
      opacity: var(--slider-disabled-opacity, var(--opacity-disabled));
    }
  }

  .label {
    color: var(--slider-label-color, var(--slider-color, var(--color-foreground)));
    font-size: var(--slider-label-font-size, var(--text-sm));
    font-weight: var(--slider-label-font-weight, var(--weight-regular));
    line-height: var(--slider-label-line-height, var(--line-height-text-sm));
    user-select: none;
  }

  .valueText {
    color: var(--slider-value-text-color, var(--slider-color, var(--color-foreground)));
    font-size: var(--slider-value-text-font-size, var(--text-sm));
    font-weight: var(--slider-value-text-font-weight, var(--weight-regular));
    line-height: var(--slider-value-text-line-height, var(--line-height-text-sm));
    text-align: right;
  }

  .control {
    position: relative;
    box-sizing: border-box;
    display: flex;
    align-items: center;
    width: 100%;
    min-height: var(--slider-control-size, 1.25rem);
    touch-action: none;
    user-select: none;
    cursor: pointer;

    &[data-orientation='vertical'] {
      flex-direction: column;
      width: var(--slider-control-size, 1.25rem);
      height: 100%;
      min-height: 0;
    }

    &[data-disabled] {
      cursor: default;
    }
  }

  .track {
    flex: 1;
    width: 100%;
    height: var(--slider-track-size, 0.375rem);
    overflow: hidden;
    border-radius: var(--slider-track-radius, var(--radius-full));
    background-color: var(--slider-track-bg, var(--color-muted));
    box-shadow: inset 0 0 0 var(--slider-track-border-width, var(--border-width-sm))
      var(--slider-track-border-color, var(--color-border));
    user-select: none;

    &[data-orientation='vertical'] {
      width: var(--slider-track-size, 0.375rem);
      height: 100%;
    }
  }

  .range {
    height: 100%;
    border-radius: var(--slider-range-radius, inherit);
    background-color: var(--slider-range-bg, var(--color-primary));

    &[data-orientation='vertical'] {
      width: 100%;
    }
  }

  .thumb {
    box-sizing: border-box;
    display: flex;
    align-items: center;
    justify-content: center;
    width: var(--slider-thumb-size, 1rem);
    height: var(--slider-thumb-size, 1rem);
    border: var(--slider-thumb-border-width, var(--border-width-sm)) solid
      var(--slider-thumb-border-color, var(--color-border));
    border-radius: var(--slider-thumb-radius, var(--radius-full));
    background-color: var(--slider-thumb-bg, var(--color-background));
    box-shadow: var(--slider-thumb-shadow, var(--shadow-sm));
    outline: 0;
    user-select: none;
    transition:
      border-color var(--slider-transition, var(--transition-default)),
      background-color var(--slider-transition, var(--transition-default)),
      box-shadow var(--slider-transition, var(--transition-default));

    &[data-dragging] {
      border-color: var(--slider-focus-ring-color, var(--color-ring));
      box-shadow:
        0 0 0 var(--border-width-sm) var(--slider-focus-ring-color, var(--color-ring)),
        var(--slider-thumb-shadow-dragging, var(--shadow-md));
    }

    &:focus-visible {
      border-color: var(--slider-focus-ring-color, var(--color-ring));
      box-shadow: 0 0 0 var(--border-width-sm) var(--slider-focus-ring-color, var(--color-ring));
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }

  .draggingIndicator {
    top: calc(-1 * var(--spacing-8));
    padding: var(--spacing-1) var(--spacing-2);
    border-radius: var(--slider-dragging-indicator-radius, var(--radius-sm));
    background-color: var(--slider-dragging-indicator-bg, var(--color-foreground));
    color: var(--slider-dragging-indicator-color, var(--color-background));
    font-size: var(--slider-dragging-indicator-font-size, var(--text-xs));
    font-weight: var(--slider-dragging-indicator-font-weight, var(--weight-medium));
    line-height: var(--slider-dragging-indicator-line-height, 1);
    white-space: nowrap;
    pointer-events: none;
  }

  .markerGroup {
    display: flex;
    justify-content: space-between;
    margin-top: var(--slider-marker-group-margin-top, var(--spacing-2));

    &[data-orientation='vertical'] {
      flex-direction: column;
      height: 100%;
      margin-top: 0;
      margin-inline-start: var(--slider-marker-group-margin-inline-start, var(--spacing-2));
    }
  }

  .marker {
    position: relative;
    color: var(--slider-marker-color, var(--color-muted-foreground));
    font-size: var(--slider-marker-font-size, var(--text-xs));
    line-height: var(--slider-marker-line-height, var(--line-height-text-xs));

    &::before {
      position: absolute;
      inset-block-start: calc(-1 * var(--spacing-2));
      inset-inline-start: 50%;
      width: var(--slider-marker-dot-size, 0.25rem);
      height: var(--slider-marker-dot-size, 0.25rem);
      border-radius: var(--radius-full);
      background-color: var(--slider-marker-dot-bg, var(--color-border));
      content: '';
      transform: translateX(-50%);
    }

    &:is([data-state='under-value'], [data-state='at-value'])::before {
      background-color: var(
        --slider-marker-dot-bg-active,
        var(--slider-range-bg, var(--color-primary))
      );
    }
  }
}
